parameters.jsCode:
const body = $input.item.json.body || {};
const PROYECTO_ID = '8c2d20d4-c635-4878-8e1b-f8e3d09d377b';
const CLIENT_ID   = '1eb0705c-2073-4ef6-9a62-fead0b132691';
const ROBERT_ID   = '0d2591a5-7b38-41bd-8ca3-54ac4548a4bc';
const ROBERT_EMAIL = 'robert@seolabagency.com';
const ROBERT_PHONE = '573183031286';
const ROBERT_SLACK = 'U052YLDC2GJ';
const title = body.title || '[DRY RUN] Reunion Operativa - SeoLab Agency';
const meeting_type = body.meeting_type || 'OPERATIVA';
const description = body.description || 'Prueba automatica de la automatizacion crear-reunion.';
let meeting_date = body.meeting_date;
if (!meeting_date) {
  const today = new Date();
  const dow = today.getDay();
  const diff = dow <= 5 ? (5 - dow) || 7 : 6;
  const fri = new Date(today);
  fri.setDate(today.getDate() + diff);
  meeting_date = fri.toISOString().split('T')[0];
}
const meeting_time = body.meeting_time || '08:30:00';
const [hh, mm] = meeting_time.split(':').map(Number);
const endHH = String((hh + 1) % 24).padStart(2, '0');
const end_time = `${endHH}:${String(mm).padStart(2, '0')}:00`;
return [{ json: {
  proyecto_id: PROYECTO_ID, client_id: CLIENT_ID, robert_id: ROBERT_ID,
  title, meeting_type, description, meeting_date, meeting_time,
  participants: [ROBERT_ID],
  calendar_start: `${meeting_date}T${meeting_time}-05:00`,
  calendar_end: `${meeting_date}T${end_time}-05:00`,
  notify_email: ROBERT_EMAIL, notify_phone: ROBERT_PHONE, notify_slack: ROBERT_SLACK
}}];

const gcal = $input.item.json;
const prep = $('Code: Preparar Datos DRY RUN').item.json;
const hasError = gcal.error !== undefined;
return [{ json: {
  ...prep,
  meet_url: !hasError ? (gcal.hangoutLink || null) : null,
  google_calendar_event_id: !hasError ? (gcal.id || null) : null,
  gcal_html_link: !hasError ? (gcal.htmlLink || null) : null,
  gcal_success: !hasError
}}];

const pg = $input.item.json;
const prev = $('Code: Extraer Meet URL').item.json;
return [{ json: {
  meeting_id: pg.id, title: prev.title, meeting_date: prev.meeting_date,
  meeting_time: prev.meeting_time, meeting_type: prev.meeting_type,
  proyecto_nombre: 'SeoLab Agency',
  meet_url: prev.meet_url || 'Google Calendar no devolvio Meet link',
  gcal_success: prev.gcal_success, gcal_html_link: prev.gcal_html_link,
  notify_slack: prev.notify_slack, notify_phone: prev.notify_phone, notify_email: prev.notify_email
}}];

